const express = require('express');
const axios = require('axios');
const app = express();

app.post('/api/proxy', async (req, res) => {
  try {
    const response = await axios.post('https://api.external.com', req.body, {
      headers: { 'Authorization': `Bearer ${process.env.API_KEY}` }
    });
    res.json(response.data);
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

public class BST<T extends Comparable<T>> {
    private Node root;
    private class Node {
        T data;
        Node left, right;
        Node(T val) { data = val; }
    }
    public void insert(T val) {
        root = insert(root, val);
    }
    private Node insert(Node node, T val) {
        if (node == null) return new Node(val);
        int cmp = val.compareTo(node.data);
        if (cmp < 0) node.left = insert(node.left, val);
        else if (cmp > 0) node.right = insert(node.right, val);
        return node;
    }
}

